181	impl<'module, 'a> Generator<'module, 'a> {
182	    #[allow(clippy::too_many_arguments)] // TODO: FIXME
183	    pub fn new(
184	        module_name: EcoString,
185	        src_path: EcoString,
186	        line_numbers: &'module LineNumbers,
187	        function_name: EcoString,
188	        function_arguments: Vec<Option<&'module EcoString>>,
189	        tracker: &'module mut UsageTracker,
190	        mut current_scope_vars: im::HashMap<EcoString, usize>,
191	    ) -> Self {
192	        let mut current_function = CurrentFunction::Module;
193	        for &name in function_arguments.iter().flatten() {
194	            // Initialise the function arguments
195	            let _ = current_scope_vars.insert(name.clone(), 0);
196	
197	            // If any of the function arguments shadow the current function then
198	            // recursion is no longer possible.
199	            if function_name.as_ref() == name {
200	                current_function = CurrentFunction::ModuleWithShadowingArgument;
201	            }
202	        }
203	        Self {
204	            tracker,
205	            module_name,
206	            src_path,
207	            line_numbers,
208	            function_name,
209	            function_arguments,
210	            tail_recursion_used: false,
211	            current_scope_vars,
212	            current_function,
213	            function_position: Position::Tail,
214	            scope_position: Position::Tail,
215	            statement_level: Vec::new(),
216	            let_assert_always_panics: false,
217	        }
218	    }
219	
220	    pub fn local_var(&mut self, name: &EcoString) -> EcoString {
221	        match self.current_scope_vars.get(name) {
222	            None => {
223	                let _ = self.current_scope_vars.insert(name.clone(), 0);
224	                maybe_escape_identifier(name)
225	            }
226	            Some(0) => maybe_escape_identifier(name),
227	            Some(n) if name == "$" => eco_format!("${n}"),
228	            Some(n) => eco_format!("{name}${n}"),
229	        }
230	    }
231	
232	    pub fn next_local_var(&mut self, name: &EcoString) -> EcoString {
233	        let next = self.current_scope_vars.get(name).map_or(0, |i| i + 1);
234	        let _ = self.current_scope_vars.insert(name.clone(), next);
235	        self.local_var(name)
236	    }
237	
238	    pub fn function_body(
239	        &mut self,
240	        body: &'a [TypedStatement],
241	        arguments: &'a [TypedArg],
242	    ) -> Document<'a> {
243	        let body = self.statements(body);
244	        if self.tail_recursion_used {
245	            self.tail_call_loop(body, arguments)
246	        } else {
247	            body
248	        }
249	    }
250	
251	    fn tail_call_loop(&mut self, body: Document<'a>, arguments: &'a [TypedArg]) -> Document<'a> {
252	        let loop_assignments = concat(arguments.iter().flat_map(Arg::get_variable_name).map(
253	            |name| {
254	                let var = maybe_escape_identifier(name);
255	                docvec!["let ", var, " = loop$", name, ";", line()]
256	            },
257	        ));
258	        docvec![
259	            "while (true) {",
260	            docvec![line(), loop_assignments, body].nest(INDENT),
261	            line(),
262	            "}"
263	        ]
264	    }
265	
266	    fn statement(&mut self, statement: &'a TypedStatement) -> Document<'a> {
267	        let expression_doc = match statement {
268	            Statement::Expression(expression) => self.expression(expression),
269	            Statement::Assignment(assignment) => self.assignment(assignment),
270	            Statement::Use(use_) => self.expression(&use_.call),
271	            Statement::Assert(assert) => self.assert(assert),
272	        };
273	        self.add_statement_level(expression_doc)
274	    }
275	
276	    fn add_statement_level(&mut self, expression: Document<'a>) -> Document<'a> {
277	        if self.statement_level.is_empty() {
278	            expression
279	        } else {
280	            let mut statements = std::mem::take(&mut self.statement_level);
281	            statements.push(expression);
282	            join(statements, line())
283	        }
284	    }
285	
286	    pub fn expression(&mut self, expression: &'a TypedExpr) -> Document<'a> {
287	        let document = match expression {
288	            TypedExpr::String { value, .. } => string(value),
289	
290	            TypedExpr::Int { value, .. } => int(value),
291	            TypedExpr::Float { float_value, .. } => float_from_value(float_value.value()),
292	
293	            TypedExpr::List { elements, tail, .. } => {
294	                self.not_in_tail_position(Some(Ordering::Strict), |this| match tail {
295	                    Some(tail) => {
296	                        this.tracker.prepend_used = true;
297	                        let tail = this.wrap_expression(tail);
298	                        prepend(
299	                            elements.iter().map(|element| this.wrap_expression(element)),
300	                            tail,
301	                        )
302	                    }
303	                    None => {
304	                        this.tracker.list_used = true;
305	                        list(elements.iter().map(|element| this.wrap_expression(element)))
306	                    }
307	                })
308	            }
309	
310	            TypedExpr::Tuple { elements, .. } => self.tuple(elements),
311	            TypedExpr::TupleIndex { tuple, index, .. } => self.tuple_index(tuple, *index),
312	
313	            TypedExpr::Case {
314	                subjects,
315	                clauses,
316	                compiled_case,
317	                ..
318	            } => decision::case(compiled_case, clauses, subjects, self),
319	
320	            TypedExpr::Call { fun, arguments, .. } => self.call(fun, arguments),
321	            TypedExpr::Fn {
322	                arguments, body, ..
323	            } => self.fn_(arguments, body),
324	
325	            TypedExpr::RecordAccess { record, label, .. } => self.record_access(record, label),
326	
327	            TypedExpr::PositionalAccess { record, index, .. } => {
328	                self.positional_access(record, *index)
329	            }
330	
331	            TypedExpr::RecordUpdate {
332	                record_assignment,
333	                constructor,
334	                arguments,
335	                ..
336	            } => self.record_update(record_assignment, constructor, arguments),
337	
338	            TypedExpr::Var {
339	                name, constructor, ..
340	            } => self.variable(name, constructor),
341	
342	            TypedExpr::Pipeline {
343	                first_value,
344	                assignments,
345	                finally,
346	                ..
347	            } => self.pipeline(first_value, assignments.as_slice(), finally),
348	
349	            TypedExpr::Block { statements, .. } => self.block(statements),
350	
351	            TypedExpr::BinOp {
352	                name, left, right, ..
353	            } => self.bin_op(name, left, right),
354	
355	            TypedExpr::Todo {
356	                message, location, ..
357	            } => self.todo(message.as_ref().map(|m| &**m), location),
358	
359	            TypedExpr::Panic {
360	                location, message, ..
361	            } => self.panic(location, message.as_ref().map(|m| &**m)),
362	
363	            TypedExpr::BitArray { segments, .. } => self.bit_array(segments),
364	
365	            TypedExpr::ModuleSelect {
366	                module_alias,
367	                label,
368	                constructor,
369	                ..
370	            } => self.module_select(module_alias, label, constructor),
371	
372	            TypedExpr::NegateBool { value, .. } => self.negate_with("!", value),
373	
374	            TypedExpr::NegateInt { value, .. } => self.negate_with("- ", value),
375	
376	            TypedExpr::Echo {
377	                expression,
378	                message,
379	                location,
380	                ..
381	            } => {
382	                let expression = expression
383	                    .as_ref()
384	                    .expect("echo with no expression outside of pipe");
385	                let expresion_doc =
386	                    self.not_in_tail_position(None, |this| this.wrap_expression(expression));
387	                self.echo(expresion_doc, message.as_deref(), location)
388	            }
389	
390	            TypedExpr::Invalid { .. } => {
391	                panic!("invalid expressions should not reach code generation")
392	            }
393	        };
394	        if expression.handles_own_return() {
395	            document
396	        } else {
397	            self.wrap_return(document)
398	        }
399	    }
400	
401	    fn negate_with(&mut self, with: &'static str, value: &'a TypedExpr) -> Document<'a> {
402	        self.not_in_tail_position(None, |this| docvec![with, this.wrap_expression(value)])
403	    }
404	
405	    fn bit_array(&mut self, segments: &'a [TypedExprBitArraySegment]) -> Document<'a> {
406	        self.tracker.bit_array_literal_used = true;
407	
408	        // Collect all the values used in segments.
409	        let segments_array = array(segments.iter().map(|segment| {
410	            let value = self.not_in_tail_position(Some(Ordering::Strict), |this| {
411	                this.wrap_expression(&segment.value)
412	            });
413	
414	            let details = self.bit_array_segment_details(segment);
415	
416	            match details.type_ {
417	                BitArraySegmentType::BitArray => {
418	                    if segment.size().is_some() {
419	                        self.tracker.bit_array_slice_used = true;
420	                        docvec!["bitArraySlice(", value, ", 0, ", details.size, ")"]
421	                    } else {
422	                        value
423	                    }
424	                }
425	                BitArraySegmentType::Int => match (details.size_value, segment.value.as_ref()) {
426	                    (Some(size_value), TypedExpr::Int { int_value, .. })
427	                        if size_value <= SAFE_INT_SEGMENT_MAX_SIZE.into()
428	                            && (&size_value % BigInt::from(8) == BigInt::ZERO) =>
429	                    {
430	                        let bytes = bit_array_segment_int_value_to_bytes(
431	                            int_value.clone(),
432	                            size_value,
433	                            segment.endianness(),
434	                        );
435	
436	                        u8_slice(&bytes)
437	                    }
438	
439	                    (Some(size_value), _) if size_value == 8.into() => value,
440	
441	                    (Some(size_value), _) if size_value <= 0.into() => nil(),
442	
443	                    _ => {
444	                        self.tracker.sized_integer_segment_used = true;
445	                        let size = details.size;
446	                        let is_big = bool(segment.endianness().is_big());
447	                        docvec!["sizedInt(", value, ", ", size, ", ", is_big, ")"]
448	                    }
449	                },
450	                BitArraySegmentType::Float => {
451	                    self.tracker.float_bit_array_segment_used = true;
452	                    let size = details.size;
453	                    let is_big = bool(details.endianness.is_big());
454	                    docvec!["sizedFloat(", value, ", ", size, ", ", is_big, ")"]
455	                }
456	                BitArraySegmentType::String(StringEncoding::Utf8) => {
457	                    self.tracker.string_bit_array_segment_used = true;
458	                    docvec!["stringBits(", value, ")"]
459	                }
460	                BitArraySegmentType::String(StringEncoding::Utf16) => {
461	                    self.tracker.string_utf16_bit_array_segment_used = true;
462	                    let is_big = bool(details.endianness.is_big());
463	                    docvec!["stringToUtf16(", value, ", ", is_big, ")"]
464	                }
465	                BitArraySegmentType::String(StringEncoding::Utf32) => {
466	                    self.tracker.string_utf32_bit_array_segment_used = true;
467	                    let is_big = bool(details.endianness.is_big());
468	                    docvec!["stringToUtf32(", value, ", ", is_big, ")"]
469	                }
470	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf8) => {
471	                    self.tracker.codepoint_bit_array_segment_used = true;
472	                    docvec!["codepointBits(", value, ")"]
473	                }
474	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf16) => {
475	                    self.tracker.codepoint_utf16_bit_array_segment_used = true;
476	                    let is_big = bool(details.endianness.is_big());
477	                    docvec!["codepointToUtf16(", value, ", ", is_big, ")"]
478	                }
479	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf32) => {
480	                    self.tracker.codepoint_utf32_bit_array_segment_used = true;
481	                    let is_big = bool(details.endianness.is_big());
482	                    docvec!["codepointToUtf32(", value, ", ", is_big, ")"]
483	                }
484	            }
485	        }));
486	
487	        docvec!["toBitArray(", segments_array, ")"]
488	    }
489	
490	    fn bit_array_segment_details(
491	        &mut self,
492	        segment: &'a TypedExprBitArraySegment,
493	    ) -> BitArraySegmentDetails<'a> {
494	        let size = segment.size();
495	        let unit = segment.unit();
496	        let (size_value, size) = match size {
497	            Some(TypedExpr::Int { int_value, .. }) => {
498	                let size_value = int_value * unit;
499	                let size = eco_format!("{}", size_value).to_doc();
500	                (Some(size_value), size)
501	            }
502	            Some(size) => {
503	                let mut size = self.not_in_tail_position(Some(Ordering::Strict), |this| {
504	                    this.wrap_expression(size)
505	                });
506	
507	                if unit != 1 {
508	                    size = size.group().append(" * ".to_doc().append(unit.to_doc()));
509	                }
510	
511	                (None, size)
512	            }
513	
514	            None => {
515	                let size_value: usize = if segment.type_.is_int() { 8 } else { 64 };
516	                (Some(BigInt::from(size_value)), docvec![size_value])
517	            }
518	        };
519	
520	        let type_ = BitArraySegmentType::from_segment(segment);
521	
522	        BitArraySegmentDetails {
523	            type_,
524	            size,
525	            size_value,
526	            endianness: segment.endianness(),
527	        }
528	    }
529	
530	    pub fn wrap_return(&mut self, document: Document<'a>) -> Document<'a> {
531	        match &self.scope_position {
532	            Position::Tail => docvec!["return ", document, ";"],
533	            Position::Expression(_) | Position::Statement => document,
534	            Position::Assign(name) => docvec![name.clone(), " = ", document, ";"],
535	        }
536	    }
537	
538	    pub fn not_in_tail_position<CompileFn, Output>(
539	        &mut self,
540	        // If ordering is None, it is inherited from the parent scope.
541	        // It will be None in cases like `!x`, where `x` can be lifted
542	        // only if the ordering is already loose.
543	        ordering: Option<Ordering>,
544	        compile: CompileFn,
545	    ) -> Output
546	    where
547	        CompileFn: Fn(&mut Self) -> Output,
548	    {
549	        let new_ordering = ordering.unwrap_or(self.scope_position.ordering());
550	
551	        let function_position = std::mem::replace(
552	            &mut self.function_position,
553	            Position::Expression(new_ordering),
554	        );
555	        let scope_position =
556	            std::mem::replace(&mut self.scope_position, Position::Expression(new_ordering));
557	
558	        let result = compile(self);
559	
560	        self.function_position = function_position;
561	        self.scope_position = scope_position;
562	        result
563	    }
564	
565	    /// Use the `_block` variable if the expression is JS statement.
566	    pub fn wrap_expression(&mut self, expression: &'a TypedExpr) -> Document<'a> {
567	        match (expression, &self.scope_position) {
568	            (_, Position::Tail | Position::Assign(_)) => self.expression(expression),
569	            (
570	                TypedExpr::Panic { .. }
571	                | TypedExpr::Todo { .. }
572	                | TypedExpr::Case { .. }
573	                | TypedExpr::Pipeline { .. }
574	                | TypedExpr::RecordUpdate {
575	                    // Record updates that assign a variable generate multiple statements
576	                    record_assignment: Some(_),
577	                    ..
578	                },
579	                Position::Expression(Ordering::Loose),
580	            ) => self.wrap_block(|this| this.expression(expression)),
581	            (
582	                TypedExpr::Panic { .. }
583	                | TypedExpr::Todo { .. }
584	                | TypedExpr::Case { .. }
585	                | TypedExpr::Pipeline { .. }
586	                | TypedExpr::RecordUpdate {
587	                    // Record updates that assign a variable generate multiple statements
588	                    record_assignment: Some(_),
589	                    ..
590	                },
591	                Position::Expression(Ordering::Strict),
592	            ) => self.immediately_invoked_function_expression(expression, |this, expr| {
593	                this.expression(expr)
594	            }),
595	            _ => self.expression(expression),
596	        }
597	    }
598	
599	    /// Wrap an expression using the `_block` variable if required due to being
600	    /// a JS statement, or in parens if required due to being an operator or
601	    /// a function literal.
602	    pub fn child_expression(&mut self, expression: &'a TypedExpr) -> Document<'a> {
603	        match expression {
604	            TypedExpr::BinOp { name, .. } if name.is_operator_to_wrap() => {}
605	            TypedExpr::Fn { .. } => {}
606	
607	            TypedExpr::Int { .. }
608	            | TypedExpr::Float { .. }
609	            | TypedExpr::String { .. }
610	            | TypedExpr::Block { .. }
611	            | TypedExpr::Pipeline { .. }
612	            | TypedExpr::Var { .. }
613	            | TypedExpr::List { .. }
614	            | TypedExpr::Call { .. }
615	            | TypedExpr::BinOp { .. }
616	            | TypedExpr::Case { .. }
617	            | TypedExpr::RecordAccess { .. }
618	            | TypedExpr::PositionalAccess { .. }
619	            | TypedExpr::ModuleSelect { .. }
620	            | TypedExpr::Tuple { .. }
621	            | TypedExpr::TupleIndex { .. }
622	            | TypedExpr::Todo { .. }
623	            | TypedExpr::Panic { .. }
624	            | TypedExpr::Echo { .. }
625	            | TypedExpr::BitArray { .. }
626	            | TypedExpr::RecordUpdate { .. }
627	            | TypedExpr::NegateBool { .. }
628	            | TypedExpr::NegateInt { .. }
629	            | TypedExpr::Invalid { .. } => return self.wrap_expression(expression),
630	        }
631	
632	        let document = self.expression(expression);
633	        match &self.scope_position {
634	            // Here the document is a return statement: `return <expr>;`
635	            // or an assignment: `_block = <expr>;`
636	            Position::Tail | Position::Assign(_) | Position::Statement => document,
637	            Position::Expression(_) => docvec!["(", document, ")"],
638	        }
639	    }
