961	    fn assert_check(
962	        &mut self,
963	        subject: &'a TypedExpr,
964	        message: &Document<'a>,
965	        location: SrcSpan,
966	    ) -> Document<'a> {
967	        let (subject_document, mut fields) = match subject {
968	            TypedExpr::Call { fun, arguments, .. } => {
969	                let argument_variables = arguments
970	                    .iter()
971	                    .map(|element| {
972	                        self.not_in_tail_position(Some(Ordering::Strict), |this| {
973	                            this.assign_to_variable(&element.value)
974	                        })
975	                    })
976	                    .collect_vec();
977	                (
978	                    self.call_with_doc_arguments(fun, argument_variables.clone()),
979	                    vec![
980	                        ("kind", string("function_call")),
981	                        (
982	                            "arguments",
983	                            array(argument_variables.into_iter().zip(arguments).map(
984	                                |(variable, argument)| {
985	                                    self.asserted_expression(
986	                                        AssertExpression::from_expression(&argument.value),
987	                                        Some(variable),
988	                                        argument.location(),
989	                                    )
990	                                },
991	                            )),
992	                        ),
993	                    ],
994	                )
995	            }
996	
997	            TypedExpr::BinOp {
998	                name, left, right, ..
999	            } => {
1000	                match name {
1001	                    BinOp::And => return self.assert_and(left, right, message, location),
1002	                    BinOp::Or => return self.assert_or(left, right, message, location),
1003	                    BinOp::Eq
1004	                    | BinOp::NotEq
1005	                    | BinOp::LtInt
1006	                    | BinOp::LtEqInt
1007	                    | BinOp::LtFloat
1008	                    | BinOp::LtEqFloat
1009	                    | BinOp::GtEqInt
1010	                    | BinOp::GtInt
1011	                    | BinOp::GtEqFloat
1012	                    | BinOp::GtFloat
1013	                    | BinOp::AddInt
1014	                    | BinOp::AddFloat
1015	                    | BinOp::SubInt
1016	                    | BinOp::SubFloat
1017	                    | BinOp::MultInt
1018	                    | BinOp::MultFloat
1019	                    | BinOp::DivInt
1020	                    | BinOp::DivFloat
1021	                    | BinOp::RemainderInt
1022	                    | BinOp::Concatenate => {}
1023	                }
1024	
1025	                let left_document = self.not_in_tail_position(Some(Ordering::Loose), |this| {
1026	                    this.assign_to_variable(left)
1027	                });
1028	                let right_document = self.not_in_tail_position(Some(Ordering::Loose), |this| {
1029	                    this.assign_to_variable(right)
1030	                });
1031	
1032	                (
1033	                    self.bin_op_with_doc_operands(
1034	                        *name,
1035	                        left_document.clone(),
1036	                        right_document.clone(),
1037	                        &left.type_(),
1038	                    )
1039	                    .surround("(", ")"),
1040	                    vec![
1041	                        ("kind", string("binary_operator")),
1042	                        ("operator", string(name.name())),
1043	                        (
1044	                            "left",
1045	                            self.asserted_expression(
1046	                                AssertExpression::from_expression(left),
1047	                                Some(left_document),
1048	                                left.location(),
1049	                            ),
1050	                        ),
1051	                        (
1052	                            "right",
1053	                            self.asserted_expression(
1054	                                AssertExpression::from_expression(right),
1055	                                Some(right_document),
1056	                                right.location(),
1057	                            ),
1058	                        ),
1059	                    ],
1060	                )
1061	            }
1062	
1063	            TypedExpr::Int { .. }
1064	            | TypedExpr::Float { .. }
1065	            | TypedExpr::String { .. }
1066	            | TypedExpr::Block { .. }
1067	            | TypedExpr::Pipeline { .. }
1068	            | TypedExpr::Var { .. }
1069	            | TypedExpr::Fn { .. }
1070	            | TypedExpr::List { .. }
1071	            | TypedExpr::Case { .. }
1072	            | TypedExpr::RecordAccess { .. }
1073	            | TypedExpr::PositionalAccess { .. }
1074	            | TypedExpr::ModuleSelect { .. }
1075	            | TypedExpr::Tuple { .. }
1076	            | TypedExpr::TupleIndex { .. }
1077	            | TypedExpr::Todo { .. }
1078	            | TypedExpr::Panic { .. }
1079	            | TypedExpr::Echo { .. }
1080	            | TypedExpr::BitArray { .. }
1081	            | TypedExpr::RecordUpdate { .. }
1082	            | TypedExpr::NegateBool { .. }
1083	            | TypedExpr::NegateInt { .. }
1084	            | TypedExpr::Invalid { .. } => (
1085	                self.wrap_expression(subject),
1086	                vec![
1087	                    ("kind", string("expression")),
1088	                    (
1089	                        "expression",
1090	                        self.asserted_expression(
1091	                            AssertExpression::from_expression(subject),
1092	                            Some("false".to_doc()),
1093	                            subject.location(),
1094	                        ),
1095	                    ),
1096	                ],
1097	            ),
1098	        };
1099	
1100	        fields.push(("start", location.start.to_doc()));
1101	        fields.push(("end", subject.location().end.to_doc()));
1102	        fields.push(("expression_start", subject.location().start.to_doc()));
1103	
1104	        docvec![
1105	            "if (",
1106	            docvec!["!", subject_document].nest(INDENT),
1107	            break_("", ""),
1108	            ") {",
1109	            docvec![
1110	                line(),
1111	                self.throw_error("assert", message, location, fields),
1112	            ]
1113	            .nest(INDENT),
1114	            line(),
1115	            "}",
1116	        ]
1117	        .group()
1118	    }
