1170	    /// In Gleam, the `&&` operator is short-circuiting, meaning that we can't
1171	    /// pre-evaluate both sides of it, and use them in the exception that is
1172	    /// thrown.
1173	    /// Instead, we need to implement this short-circuiting logic ourself.
1174	    ///
1175	    /// If we short-circuit, we must leave the second expression unevaluated,
1176	    /// and signal that using the `unevaluated` variant, as detailed in the
1177	    /// exception format. For the first expression, we know it must be `false`,
1178	    /// otherwise we would have continued by evaluating the second expression.
1179	    ///
1180	    /// Similarly, if we do evaluate the second expression and fail, we know
1181	    /// that the first expression must have evaluated to `true`, and the second
1182	    /// to `false`. This way, we avoid needing to evaluate either expression
1183	    /// twice.
1184	    ///
1185	    /// The generated code then looks something like this:
1186	    /// ```javascript
1187	    /// if (expr1) {
1188	    ///   if (!expr2) {
1189	    ///     <throw exception>
1190	    ///   }
1191	    /// } else {
1192	    ///   <throw exception>
1193	    /// }
1194	    /// ```
1195	    ///
1196	    fn assert_and(
1197	        &mut self,
1198	        left: &'a TypedExpr,
1199	        right: &'a TypedExpr,
1200	        message: &Document<'a>,
1201	        location: SrcSpan,
1202	    ) -> Document<'a> {
1203	        let left_kind = AssertExpression::from_expression(left);
1204	        let right_kind = AssertExpression::from_expression(right);
1205	
1206	        let fields_if_short_circuiting = vec![
1207	            ("kind", string("binary_operator")),
1208	            ("operator", string("&&")),
1209	            (
1210	                "left",
1211	                self.asserted_expression(left_kind, Some("false".to_doc()), left.location()),
1212	            ),
1213	            (
1214	                "right",
1215	                self.asserted_expression(AssertExpression::Unevaluated, None, right.location()),
1216	            ),
1217	            ("start", location.start.to_doc()),
1218	            ("end", right.location().end.to_doc()),
1219	            ("expression_start", left.location().start.to_doc()),
1220	        ];
1221	
1222	        let fields = vec![
1223	            ("kind", string("binary_operator")),
1224	            ("operator", string("&&")),
1225	            (
1226	                "left",
1227	                self.asserted_expression(left_kind, Some("true".to_doc()), left.location()),
1228	            ),
1229	            (
1230	                "right",
1231	                self.asserted_expression(right_kind, Some("false".to_doc()), right.location()),
1232	            ),
1233	            ("start", location.start.to_doc()),
1234	            ("end", right.location().end.to_doc()),
1235	            ("expression_start", left.location().start.to_doc()),
1236	        ];
1237	
1238	        let left_value =
1239	            self.not_in_tail_position(Some(Ordering::Loose), |this| this.wrap_expression(left));
1240	
1241	        let right_value = self.not_in_tail_position(Some(Ordering::Strict), |this| {
1242	            this.negate_bool_expression(right)
1243	        });
1244	
1245	        let right_check = docvec![
1246	            line(),
1247	            "if (",
1248	            right_value.nest(INDENT),
1249	            ") {",
1250	            docvec![
1251	                line(),
1252	                self.throw_error("assert", message, location, fields)
1253	            ]
1254	            .nest(INDENT),
1255	            line(),
1256	            "}",
1257	        ];
1258	
1259	        docvec![
1260	            "if (",
1261	            left_value.nest(INDENT),
1262	            ") {",
1263	            right_check.nest(INDENT),
1264	            line(),
1265	            "} else {",
1266	            docvec![
1267	                line(),
1268	                self.throw_error("assert", message, location, fields_if_short_circuiting)
