1276	    /// Similar to `&&`, `||` is also short-circuiting in Gleam. However, if `||`
1277	    /// short-circuits, that's because the first expression evaluated to `true`,
1278	    /// meaning the whole assertion succeeds. This allows us to directly use the
1279	    /// `||` operator in JavaScript.
1280	    ///
1281	    /// The only difference is that due to the nature of `||`, if the assertion fails,
1282	    /// we know that both sides must have evaluated to `false`, so we don't
1283	    /// need to store the values of them in variables beforehand.
1284	    fn assert_or(
1285	        &mut self,
1286	        left: &'a TypedExpr,
1287	        right: &'a TypedExpr,
1288	        message: &Document<'a>,
1289	        location: SrcSpan,
1290	    ) -> Document<'a> {
1291	        let fields = vec![
1292	            ("kind", string("binary_operator")),
1293	            ("operator", string("||")),
1294	            (
1295	                "left",
1296	                self.asserted_expression(
1297	                    AssertExpression::from_expression(left),
1298	                    Some("false".to_doc()),
1299	                    left.location(),
1300	                ),
1301	            ),
1302	            (
1303	                "right",
1304	                self.asserted_expression(
1305	                    AssertExpression::from_expression(right),
1306	                    Some("false".to_doc()),
1307	                    right.location(),
1308	                ),
1309	            ),
1310	            ("start", location.start.to_doc()),
1311	            ("end", right.location().end.to_doc()),
1312	            ("expression_start", left.location().start.to_doc()),
1313	        ];
1314	
1315	        let left_value =
1316	            self.not_in_tail_position(Some(Ordering::Loose), |this| this.child_expression(left));
1317	
1318	        let right_value =
1319	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(right));
1320	
1321	        docvec![
1322	            line(),
1323	            "if (",
1324	            docvec!["!(", left_value, " || ", right_value, ")"].nest(INDENT),
1325	            ") {",
1326	            docvec![
1327	                line(),
1328	                self.throw_error("assert", message, location, fields)
1329	            ]
1330	            .nest(INDENT),
1331	            line(),
1332	            "}",
1333	        ]
1334	    }
