1338	            self.expression(value)
1339	        } else {
1340	            let value = self.wrap_expression(value);
1341	            let variable = self.next_local_var(&ASSIGNMENT_VAR.into());
1342	            let assignment = docvec!["let ", variable.clone(), " = ", value, ";"];
1343	            self.statement_level.push(assignment);
1344	            variable.to_doc()
1345	        }
