1399	    fn call_with_doc_arguments(
1400	        &mut self,
1401	        fun: &'a TypedExpr,
1402	        arguments: Vec<Document<'a>>,
1403	    ) -> Document<'a> {
1404	        match fun {
1405	            // Qualified record construction
1406	            TypedExpr::ModuleSelect {
1407	                constructor: ModuleValueConstructor::Record { name, .. },
1408	                module_alias,
1409	                ..
1410	            } => self.wrap_return(construct_record(Some(module_alias), name, arguments)),
1411	
1412	            // Record construction
1413	            TypedExpr::Var {
1414	                constructor:
1415	                    ValueConstructor {
1416	                        variant: ValueConstructorVariant::Record { .. },
1417	                        type_,
1418	                        ..
1419	                    },
1420	                name,
1421	                ..
1422	            } => {
1423	                if type_.is_result_constructor() {
1424	                    if name == "Ok" {
1425	                        self.tracker.ok_used = true;
1426	                    } else if name == "Error" {
1427	                        self.tracker.error_used = true;
1428	                    }
1429	                }
1430	                self.wrap_return(construct_record(None, name, arguments))
1431	            }
1432	
1433	            // Tail call optimisation. If we are calling the current function
1434	            // and we are in tail position we can avoid creating a new stack
1435	            // frame, enabling recursion with constant memory usage.
1436	            TypedExpr::Var { name, .. }
1437	                if self.function_name == *name
1438	                    && self.current_function.can_recurse()
1439	                    && self.function_position.is_tail()
1440	                    && self.current_scope_vars.get(name) == Some(&0) =>
1441	            {
1442	                let mut docs = Vec::with_capacity(arguments.len() * 4);
1443	                // Record that tail recursion is happening so that we know to
1444	                // render the loop at the top level of the function.
1445	                self.tail_recursion_used = true;
1446	
1447	                for (i, (element, argument)) in arguments
1448	                    .into_iter()
1449	                    .zip(&self.function_arguments)
1450	                    .enumerate()
1451	                {
1452	                    if i != 0 {
1453	                        docs.push(line());
1454	                    }
1455	                    // Create an assignment for each variable created by the function arguments
1456	                    if let Some(name) = argument {
1457	                        docs.push("loop$".to_doc());
1458	                        docs.push(name.to_doc());
1459	                        docs.push(" = ".to_doc());
1460	                    }
1461	                    // Render the value given to the function. Even if it is not
1462	                    // assigned we still render it because the expression may
1463	                    // have some side effects.
1464	                    docs.push(element);
1465	                    docs.push(";".to_doc());
1466	                }
1467	                docs.to_doc()
1468	            }
1469	
1470	            TypedExpr::Int { .. }
1471	            | TypedExpr::Float { .. }
1472	            | TypedExpr::String { .. }
1473	            | TypedExpr::Block { .. }
1474	            | TypedExpr::Pipeline { .. }
1475	            | TypedExpr::Var { .. }
1476	            | TypedExpr::Fn { .. }
1477	            | TypedExpr::List { .. }
1478	            | TypedExpr::Call { .. }
1479	            | TypedExpr::BinOp { .. }
1480	            | TypedExpr::Case { .. }
1481	            | TypedExpr::RecordAccess { .. }
1482	            | TypedExpr::PositionalAccess { .. }
1483	            | TypedExpr::ModuleSelect { .. }
1484	            | TypedExpr::Tuple { .. }
1485	            | TypedExpr::TupleIndex { .. }
1486	            | TypedExpr::Todo { .. }
1487	            | TypedExpr::Panic { .. }
1488	            | TypedExpr::Echo { .. }
1489	            | TypedExpr::BitArray { .. }
1490	            | TypedExpr::RecordUpdate { .. }
1491	            | TypedExpr::NegateBool { .. }
1492	            | TypedExpr::NegateInt { .. }
1493	            | TypedExpr::Invalid { .. } => {
1494	                let fun = self.not_in_tail_position(None, |this| -> Document<'_> {
1495	                    let is_fn_literal = matches!(fun, TypedExpr::Fn { .. });
1496	                    let fun = this.wrap_expression(fun);
1497	                    if is_fn_literal {
1498	                        docvec!["(", fun, ")"]
1499	                    } else {
1500	                        fun
1501	                    }
1502	                });
1503	                let arguments = call_arguments(arguments);
1504	                self.wrap_return(docvec![fun, arguments])
1505	            }
1506	        }
1507	    }
