1509	    fn fn_(&mut self, arguments: &'a [TypedArg], body: &'a [TypedStatement]) -> Document<'a> {
1510	        // New function, this is now the tail position
1511	        let function_position = std::mem::replace(&mut self.function_position, Position::Tail);
1512	        let scope_position = std::mem::replace(&mut self.scope_position, Position::Tail);
1513	
1514	        // And there's a new scope
1515	        let scope = self.current_scope_vars.clone();
1516	        for name in arguments.iter().flat_map(Arg::get_variable_name) {
1517	            let _ = self.current_scope_vars.insert(name.clone(), 0);
1518	        }
1519	
1520	        // This is a new function so track that so that we don't
1521	        // mistakenly trigger tail call optimisation
1522	        let mut current_function = CurrentFunction::Anonymous;
1523	        std::mem::swap(&mut self.current_function, &mut current_function);
1524	
1525	        // Generate the function body
1526	        let result = self.statements(body);
1527	
1528	        // Reset function name, scope, and tail position tracking
1529	        self.function_position = function_position;
1530	        self.scope_position = scope_position;
1531	        self.current_scope_vars = scope;
1532	        std::mem::swap(&mut self.current_function, &mut current_function);
1533	
1534	        docvec![
1535	            docvec![
1536	                fun_arguments(arguments, false),
1537	                " => {",
1538	                break_("", " "),
1539	                result
1540	            ]
1541	            .nest(INDENT)
1542	            .append(break_("", " "))
1543	            .group(),
1544	            "}",
1545	        ]
1546	    }
