1611	    fn div_int(&mut self, left: &'a TypedExpr, right: &'a TypedExpr) -> Document<'a> {
1612	        let left_doc =
1613	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(left));
1614	        let right_doc =
1615	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(right));
1616	
1617	        // If we have a constant value divided by zero then it's safe to replace
1618	        // it directly with 0.
1619	        if left.is_literal() && right.is_zero_compile_time_number() {
1620	            "0".to_doc()
1621	        } else if right.is_non_zero_compile_time_number() {
1622	            let division = if let TypedExpr::BinOp { .. } = left {
1623	                docvec![left_doc.surround("(", ")"), " / ", right_doc]
1624	            } else {
1625	                docvec![left_doc, " / ", right_doc]
1626	            };
1627	            docvec!["globalThis.Math.trunc", wrap_arguments([division])]
1628	        } else {
1629	            self.tracker.int_division_used = true;
1630	            docvec!["divideInt", wrap_arguments([left_doc, right_doc])]
1631	        }
1632	    }
