1678	    fn equal(
1679	        &mut self,
1680	        left: &'a TypedExpr,
1681	        right: &'a TypedExpr,
1682	        should_be_equal: bool,
1683	    ) -> Document<'a> {
1684	        // If it is a simple scalar type then we can use JS' reference identity
1685	        if is_js_scalar(left.type_()) {
1686	            let left_doc = self
1687	                .not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(left));
1688	            let right_doc = self
1689	                .not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(right));
1690	            let operator = if should_be_equal { " === " } else { " !== " };
1691	            return docvec![left_doc, operator, right_doc];
1692	        }
1693	
1694	        // For comparison with singleton custom types, ie, one with no fields.
1695	        // If you have some code like this
1696	        // ```gleam
1697	        //  pub type Wibble {
1698	        //    Wibble
1699	        //    Wobble
1700	        //  }
1701	
1702	        //  pub fn is_wibble(w: Wibble) -> Bool {
1703	        //    w == Wibble
1704	        //  }
1705	        // ```
1706	        // Instead of `isEqual(w, new Wibble())`, generate `w instanceof Wibble`
1707	        // because the first approach needs to construct a new Wibble, and then call the isEqual function,
1708	        // which supports any shape of data, and so does a lot of extra logic which isn't necessary.
1709	
1710	        if let Some(doc) = self.singleton_variant_equality(left, right, should_be_equal) {
1711	            return doc;
1712	        }
1713	
1714	        if let Some(doc) = self.singleton_variant_equality(right, left, should_be_equal) {
1715	            return doc;
1716	        }
1717	
1718	        // Other types must be compared using structural equality
1719	        let left =
1720	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.wrap_expression(left));
1721	        let right =
1722	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.wrap_expression(right));
1723	
1724	        self.prelude_equal_call(should_be_equal, left, right)
1725	    }
