1727	    fn singleton_variant_equality(
1728	        &mut self,
1729	        left: &'a TypedExpr,
1730	        right: &'a TypedExpr,
1731	        should_be_equal: bool,
1732	    ) -> Option<Document<'a>> {
1733	        match right {
1734	            TypedExpr::Var {
1735	                constructor:
1736	                    ValueConstructor {
1737	                        variant: ValueConstructorVariant::Record { arity: 0, name, .. },
1738	                        ..
1739	                    },
1740	                ..
1741	            } => {
1742	                let left_doc = self.not_in_tail_position(Some(Ordering::Strict), |this| {
1743	                    this.wrap_expression(left)
1744	                });
1745	                Some(self.singleton_equal(left_doc, None, name, should_be_equal))
1746	            }
1747	            TypedExpr::ModuleSelect {
1748	                module_alias,
1749	                constructor: ModuleValueConstructor::Record { arity: 0, name, .. },
1750	                ..
1751	            } => {
1752	                let left_doc = self.not_in_tail_position(Some(Ordering::Strict), |this| {
1753	                    this.wrap_expression(left)
1754	                });
1755	                Some(self.singleton_equal(left_doc, Some(module_alias), name, should_be_equal))
1756	            }
1757	            TypedExpr::Int { .. }
1758	            | TypedExpr::Float { .. }
1759	            | TypedExpr::String { .. }
1760	            | TypedExpr::Block { .. }
1761	            | TypedExpr::Pipeline { .. }
1762	            | TypedExpr::Var { .. }
1763	            | TypedExpr::Fn { .. }
1764	            | TypedExpr::List { .. }
1765	            | TypedExpr::Call { .. }
1766	            | TypedExpr::BinOp { .. }
1767	            | TypedExpr::Case { .. }
1768	            | TypedExpr::RecordAccess { .. }
1769	            | TypedExpr::PositionalAccess { .. }
1770	            | TypedExpr::ModuleSelect { .. }
1771	            | TypedExpr::Tuple { .. }
1772	            | TypedExpr::TupleIndex { .. }
1773	            | TypedExpr::Todo { .. }
1774	            | TypedExpr::Panic { .. }
1775	            | TypedExpr::Echo { .. }
1776	            | TypedExpr::BitArray { .. }
