1804	    fn equal_with_doc_operands(
1805	        &mut self,
1806	        left: Document<'a>,
1807	        right: Document<'a>,
1808	        type_: Arc<Type>,
1809	        should_be_equal: bool,
1810	    ) -> Document<'a> {
1811	        // If it is a simple scalar type then we can use JS' reference identity
1812	        if is_js_scalar(type_) {
1813	            let operator = if should_be_equal { " === " } else { " !== " };
1814	            return docvec![left, operator, right];
1815	        }
1816	
1817	        // Other types must be compared using structural equality
1818	        self.prelude_equal_call(should_be_equal, left, right)
1819	    }
