1821	    pub(super) fn prelude_equal_call(
1822	        &mut self,
1823	        should_be_equal: bool,
1824	        left: Document<'a>,
1825	        right: Document<'a>,
1826	    ) -> Document<'a> {
1827	        // Record that we need to import the prelude's isEqual function into the module
1828	        self.tracker.object_equality_used = true;
1829	        // Construct the call
1830	        let arguments = wrap_arguments([left, right]);
1831	        let operator = if should_be_equal {
1832	            "isEqual"
1833	        } else {
1834	            "!isEqual"
1835	        };
1836	        docvec![operator, arguments]
1837	    }
