1839	    fn print_bin_op(
1840	        &mut self,
1841	        left: &'a TypedExpr,
1842	        right: &'a TypedExpr,
1843	        op: &'a str,
1844	    ) -> Document<'a> {
1845	        let left =
1846	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(left));
1847	        let right =
1848	            self.not_in_tail_position(Some(Ordering::Strict), |this| this.child_expression(right));
1849	        docvec![left, " ", op, " ", right]
