1852	    pub(super) fn bin_op_with_doc_operands(
1853	        &mut self,
1854	        name: BinOp,
1855	        left: Document<'a>,
1856	        right: Document<'a>,
1857	        type_: &Arc<Type>,
1858	    ) -> Document<'a> {
1859	        match name {
1860	            BinOp::And => docvec![left, " && ", right],
1861	            BinOp::Or => docvec![left, " || ", right],
1862	            BinOp::LtInt | BinOp::LtFloat => docvec![left, " < ", right],
1863	            BinOp::LtEqInt | BinOp::LtEqFloat => docvec![left, " <= ", right],
1864	            BinOp::Eq => self.equal_with_doc_operands(left, right, type_.clone(), true),
1865	            BinOp::NotEq => self.equal_with_doc_operands(left, right, type_.clone(), false),
1866	            BinOp::GtInt | BinOp::GtFloat => docvec![left, " > ", right],
1867	            BinOp::GtEqInt | BinOp::GtEqFloat => docvec![left, " >= ", right],
1868	            BinOp::Concatenate | BinOp::AddInt | BinOp::AddFloat => {
1869	                docvec![left, " + ", right]
1870	            }
1871	            BinOp::SubInt | BinOp::SubFloat => docvec![left, " - ", right],
1872	            BinOp::MultInt | BinOp::MultFloat => docvec![left, " * ", right],
1873	            BinOp::RemainderInt => {
1874	                self.tracker.int_remainder_used = true;
1875	                docvec!["remainderInt", wrap_arguments([left, right])]
1876	            }
1877	            BinOp::DivInt => {
1878	                self.tracker.int_division_used = true;
1879	                docvec!["divideInt", wrap_arguments([left, right])]
1880	            }
1881	            BinOp::DivFloat => {
1882	                self.tracker.float_division_used = true;
1883	                docvec!["divideFloat", wrap_arguments([left, right])]
1884	            }
1885	        }
1886	    }
