1974	    pub(crate) fn constant_expression(
1975	        &mut self,
1976	        context: Context,
1977	        expression: &'a TypedConstant,
1978	    ) -> Document<'a> {
1979	        match expression {
1980	            Constant::Int { value, .. } => int(value),
1981	            Constant::Float { value, .. } => float(value),
1982	            Constant::String { value, .. } => string(value),
1983	            Constant::Tuple { elements, .. } => array(
1984	                elements
1985	                    .iter()
1986	                    .map(|element| self.constant_expression(context, element)),
1987	            ),
1988	
1989	            Constant::List { elements, tail, .. } => {
1990	                self.tracker.list_used = true;
1991	
1992	                let tail_elements = tail
1993	                    .as_deref()
1994	                    .and_then(|tail| tail.list_elements())
1995	                    .unwrap_or_default();
1996	
1997	                let list = list(
1998	                    elements
1999	                        .iter()
2000	                        .chain(tail_elements)
2001	                        .map(|element| self.constant_expression(context, element)),
2002	                );
2003	
2004	                match context {
2005	                    Context::Constant => docvec!["/* @__PURE__ */ ", list],
2006	                    Context::Guard => list,
2007	                }
2008	            }
2009	
2010	            Constant::Record { type_, name, .. } if type_.is_bool() && name == "True" => {
2011	                "true".to_doc()
2012	            }
2013	            Constant::Record { type_, name, .. } if type_.is_bool() && name == "False" => {
2014	                "false".to_doc()
2015	            }
2016	            Constant::Record { type_, .. } if type_.is_nil() => "undefined".to_doc(),
2017	
2018	            Constant::Record {
2019	                arguments,
2020	                module,
2021	                name,
2022	                tag,
2023	                type_,
2024	                ..
2025	            } => {
2026	                if module.is_none() && type_.is_result() {
2027	                    if tag == "Ok" {
2028	                        self.tracker.ok_used = true;
2029	                    } else {
2030	                        self.tracker.error_used = true;
2031	                    }
2032	                }
2033	
2034	                // If there's no arguments and the type is a function that takes
2035	                // arguments then this is the constructor being referenced, not the
2036	                // function being called.
2037	                if let Some(arity) = type_.fn_arity()
2038	                    && arguments.is_empty()
2039	                    && arity != 0
2040	                {
2041	                    let arity = arity as u16;
2042	                    return record_constructor(type_.clone(), None, name, arity, self.tracker);
2043	                }
2044	
2045	                // Record updates are fully expanded during type checking, so we just handle arguments
2046	                let field_values = arguments
2047	                    .iter()
2048	                    .map(|argument| self.constant_expression(context, &argument.value))
2049	                    .collect_vec();
2050	
2051	                let constructor = construct_record(
2052	                    module.as_ref().map(|(module, _)| module.as_str()),
2053	                    name,
2054	                    field_values,
2055	                );
2056	                match context {
2057	                    Context::Constant => docvec!["/* @__PURE__ */ ", constructor],
2058	                    Context::Guard => constructor,
2059	                }
2060	            }
2061	            Constant::BitArray { segments, .. } => {
2062	                let bit_array = self.constant_bit_array(segments, context);
2063	                match context {
2064	                    Context::Constant => docvec!["/* @__PURE__ */ ", bit_array],
2065	                    Context::Guard => bit_array,
2066	                }
2067	            }
2068	
2069	            Constant::Var { name, module, .. } => {
2070	                match (module, context) {
2071	                    (None, Context::Guard) => self.local_var(name).to_doc(),
2072	                    (None, Context::Constant) => maybe_escape_identifier(name).to_doc(),
2073	                    (Some((module, _)), _) => {
2074	                        // JS keywords can be accessed here, but we must escape anyway
2075	                        // as we escape when exporting such names in the first place,
2076	                        // and the imported name has to match the exported name.
2077	                        docvec!["$", module, ".", maybe_escape_identifier(name)]
2078	                    }
2079	                }
2080	            }
2081	
2082	            Constant::StringConcatenation { left, right, .. } => {
2083	                let left = self.constant_expression(context, left);
2084	                let right = self.constant_expression(context, right);
2085	                docvec![left, " + ", right]
2086	            }
2087	
2088	            Constant::RecordUpdate { .. } => {
2089	                panic!("record updates should not reach code generation")
2090	            }
2091	
2092	            Constant::Invalid { .. } => {
2093	                panic!("invalid constants should not reach code generation")
2094	            }
2095	        }
2096	    }
