2098	    fn constant_bit_array(
2099	        &mut self,
2100	        segments: &'a [TypedConstantBitArraySegment],
2101	        context: Context,
2102	    ) -> Document<'a> {
2103	        self.tracker.bit_array_literal_used = true;
2104	        let segments_array = array(segments.iter().map(|segment| {
2105	            let value = match context {
2106	                Context::Constant => self.constant_expression(context, &segment.value),
2107	                Context::Guard => self.guard_constant_expression(&segment.value),
2108	            };
2109	
2110	            let details = self.constant_bit_array_segment_details(segment, context);
2111	
2112	            match details.type_ {
2113	                BitArraySegmentType::BitArray => {
2114	                    if segment.size().is_some() {
2115	                        self.tracker.bit_array_slice_used = true;
2116	                        docvec!["bitArraySlice(", value, ", 0, ", details.size, ")"]
2117	                    } else {
2118	                        value
2119	                    }
2120	                }
2121	                BitArraySegmentType::Int => match (details.size_value, segment.value.as_ref()) {
2122	                    (Some(size_value), Constant::Int { int_value, .. })
2123	                        if size_value <= SAFE_INT_SEGMENT_MAX_SIZE.into()
2124	                            && (&size_value % BigInt::from(8) == BigInt::ZERO) =>
2125	                    {
2126	                        let bytes = bit_array_segment_int_value_to_bytes(
2127	                            int_value.clone(),
2128	                            size_value,
2129	                            segment.endianness(),
2130	                        );
2131	
2132	                        u8_slice(&bytes)
2133	                    }
2134	
2135	                    (Some(size_value), _) if size_value == 8.into() => value,
2136	
2137	                    (Some(size_value), _) if size_value <= 0.into() => nil(),
2138	
2139	                    _ => {
2140	                        self.tracker.sized_integer_segment_used = true;
2141	                        let size = details.size;
2142	                        let is_big = bool(segment.endianness().is_big());
2143	                        docvec!["sizedInt(", value, ", ", size, ", ", is_big, ")"]
2144	                    }
2145	                },
2146	                BitArraySegmentType::Float => {
2147	                    self.tracker.float_bit_array_segment_used = true;
2148	                    let size = details.size;
2149	                    let is_big = bool(details.endianness.is_big());
2150	                    docvec!["sizedFloat(", value, ", ", size, ", ", is_big, ")"]
2151	                }
2152	                BitArraySegmentType::String(StringEncoding::Utf8) => {
2153	                    self.tracker.string_bit_array_segment_used = true;
2154	                    docvec!["stringBits(", value, ")"]
2155	                }
2156	                BitArraySegmentType::String(StringEncoding::Utf16) => {
2157	                    self.tracker.string_utf16_bit_array_segment_used = true;
2158	                    let is_big = bool(details.endianness.is_big());
2159	                    docvec!["stringToUtf16(", value, ", ", is_big, ")"]
2160	                }
2161	                BitArraySegmentType::String(StringEncoding::Utf32) => {
2162	                    self.tracker.string_utf32_bit_array_segment_used = true;
2163	                    let is_big = bool(details.endianness.is_big());
2164	                    docvec!["stringToUtf32(", value, ", ", is_big, ")"]
2165	                }
2166	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf8) => {
2167	                    self.tracker.codepoint_bit_array_segment_used = true;
2168	                    docvec!["codepointBits(", value, ")"]
2169	                }
2170	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf16) => {
2171	                    self.tracker.codepoint_utf16_bit_array_segment_used = true;
2172	                    let is_big = bool(details.endianness.is_big());
2173	                    docvec!["codepointToUtf16(", value, ", ", is_big, ")"]
2174	                }
2175	                BitArraySegmentType::UtfCodepoint(StringEncoding::Utf32) => {
2176	                    self.tracker.codepoint_utf32_bit_array_segment_used = true;
2177	                    let is_big = bool(details.endianness.is_big());
2178	                    docvec!["codepointToUtf32(", value, ", ", is_big, ")"]
2179	                }
2180	            }
2181	        }));
2182	
2183	        docvec!["toBitArray(", segments_array, ")"]
2184	    }
