2186	    fn constant_bit_array_segment_details(
2187	        &mut self,
2188	        segment: &'a TypedConstantBitArraySegment,
2189	        context: Context,
2190	    ) -> BitArraySegmentDetails<'a> {
2191	        let size = segment.size();
2192	        let unit = segment.unit();
2193	        let (size_value, size) = match size {
2194	            Some(Constant::Int { int_value, .. }) => {
2195	                let size_value = int_value * unit;
2196	                let size = eco_format!("{}", size_value).to_doc();
2197	                (Some(size_value), size)
2198	            }
2199	
2200	            Some(size) => {
2201	                let mut size = match context {
2202	                    Context::Constant => self.constant_expression(context, size),
2203	                    Context::Guard => self.guard_constant_expression(size),
2204	                };
2205	                if unit != 1 {
2206	                    size = size.group().append(" * ".to_doc().append(unit.to_doc()));
2207	                }
2208	
2209	                (None, size)
2210	            }
2211	
2212	            None => {
2213	                let size_value: usize = if segment.type_.is_int() { 8 } else { 64 };
2214	                (Some(BigInt::from(size_value)), docvec![size_value])
2215	            }
2216	        };
2217	
2218	        let type_ = BitArraySegmentType::from_segment(segment);
2219	
2220	        BitArraySegmentDetails {
2221	            type_,
2222	            size,
2223	            size_value,
2224	            endianness: segment.endianness(),
2225	        }
2226	    }
