2228	    pub(crate) fn guard(&mut self, guard: &'a TypedClauseGuard) -> Document<'a> {
2229	        match guard {
2230	            ClauseGuard::Block { value, .. } => self.guard(value).surround("(", ")"),
2231	
2232	            ClauseGuard::BinaryOperator {
2233	                left,
2234	                right,
2235	                operator,
2236	                ..
2237	            } => {
2238	                let left_document = self.wrapped_guard(left);
2239	                let right_document = self.wrapped_guard(right);
2240	
2241	                let operator = match operator {
2242	                    BinOp::Eq if is_js_scalar(left.type_()) => "===",
2243	                    BinOp::NotEq if is_js_scalar(left.type_()) => "!==",
2244	                    BinOp::Eq | BinOp::NotEq => {
2245	                        let should_be_equal = *operator == BinOp::Eq;
2246	
2247	                        // Handle singleton equality optimization for guards
2248	                        if let Some(doc) =
2249	                            self.singleton_variant_guard_equality(left, right, should_be_equal)
2250	                        {
2251	                            return doc;
2252	                        }
2253	
2254	                        if let Some(doc) =
2255	                            self.singleton_variant_guard_equality(right, left, should_be_equal)
2256	                        {
2257	                            return doc;
2258	                        }
2259	
2260	                        let left_doc = self.guard(left);
2261	                        let right_doc = self.guard(right);
2262	                        return self.prelude_equal_call(should_be_equal, left_doc, right_doc);
2263	                    }
2264	
2265	                    BinOp::GtFloat | BinOp::GtInt => ">",
2266	                    BinOp::GtEqFloat | BinOp::GtEqInt => ">=",
2267	                    BinOp::LtFloat | BinOp::LtInt => "<",
2268	                    BinOp::LtEqFloat | BinOp::LtEqInt => "<=",
2269	
2270	                    BinOp::AddFloat | BinOp::AddInt | BinOp::Concatenate => "+",
2271	                    BinOp::SubFloat | BinOp::SubInt => "-",
2272	                    BinOp::MultFloat | BinOp::MultInt => "*",
2273	
2274	                    BinOp::DivFloat => {
2275	                        self.tracker.float_division_used = true;
2276	                        return docvec![
2277	                            "divideFloat",
2278	                            wrap_arguments([left_document, right_document])
2279	                        ];
2280	                    }
2281	
2282	                    BinOp::DivInt => {
2283	                        self.tracker.int_division_used = true;
2284	                        return docvec![
2285	                            "divideInt",
2286	                            wrap_arguments([left_document, right_document])
2287	                        ];
2288	                    }
2289	
2290	                    BinOp::RemainderInt => {
2291	                        self.tracker.int_remainder_used = true;
2292	                        return docvec![
2293	                            "remainderInt",
2294	                            wrap_arguments([left_document, right_document])
2295	                        ];
2296	                    }
2297	
2298	                    BinOp::And => "&&",
2299	                    BinOp::Or => "||",
2300	                };
2301	
2302	                docvec![left_document, " ", operator, " ", right_document]
2303	            }
2304	
2305	            ClauseGuard::Var { name, .. } => self.local_var(name).to_doc(),
2306	
2307	            ClauseGuard::TupleIndex { tuple, index, .. } => {
2308	                docvec![self.guard(tuple,), "[", index, "]"]
2309	            }
2310	
2311	            ClauseGuard::FieldAccess {
2312	                label, container, ..
2313	            } => docvec![self.guard(container), ".", maybe_escape_property(label)],
2314	
2315	            ClauseGuard::ModuleSelect {
2316	                module_alias,
2317	                label,
2318	                ..
2319	            } => docvec!["$", module_alias, ".", label],
2320	
2321	            ClauseGuard::Not { expression, .. } => docvec!["!", self.guard(expression,)],
2322	
2323	            ClauseGuard::Constant(constant) => self.guard_constant_expression(constant),
2324	        }
2325	    }
