2327	    fn singleton_variant_guard_equality(
2328	        &mut self,
2329	        left: &'a TypedClauseGuard,
2330	        right: &'a TypedClauseGuard,
2331	        should_be_equal: bool,
2332	    ) -> Option<Document<'a>> {
2333	        if let ClauseGuard::Constant(Constant::Record {
2334	            record_constructor: Some(constructor),
2335	            module,
2336	            name,
2337	            ..
2338	        }) = right
2339	            && let ValueConstructorVariant::Record { arity: 0, .. } = constructor.variant
2340	        {
2341	            let left_doc = self.guard(left);
2342	            return Some(self.singleton_equal(
2343	                left_doc,
2344	                module.as_ref().map(|(module, _)| module.as_str()),
2345	                name,
2346	                should_be_equal,
2347	            ));
2348	        }
2349	        None
2350	    }
