2352	    fn wrapped_guard(&mut self, guard: &'a TypedClauseGuard) -> Document<'a> {
2353	        match guard {
2354	            ClauseGuard::Var { .. }
2355	            | ClauseGuard::TupleIndex { .. }
2356	            | ClauseGuard::Constant(_)
2357	            | ClauseGuard::Not { .. }
2358	            | ClauseGuard::FieldAccess { .. }
2359	            | ClauseGuard::Block { .. } => self.guard(guard),
2360	
2361	            ClauseGuard::BinaryOperator { .. } | ClauseGuard::ModuleSelect { .. } => {
2362	                docvec!["(", self.guard(guard), ")"]
2363	            }
2364	        }
2365	    }
