2367	    fn guard_constant_expression(&mut self, expression: &'a TypedConstant) -> Document<'a> {
2368	        match expression {
2369	            Constant::Tuple { elements, .. } => array(
2370	                elements
2371	                    .iter()
2372	                    .map(|element| self.guard_constant_expression(element)),
2373	            ),
2374	
2375	            Constant::List { elements, .. } => {
2376	                self.tracker.list_used = true;
2377	                list(
2378	                    elements
2379	                        .iter()
2380	                        .map(|element| self.guard_constant_expression(element)),
2381	                )
2382	            }
2383	            Constant::Record { type_, name, .. } if type_.is_bool() && name == "True" => {
2384	                "true".to_doc()
2385	            }
2386	            Constant::Record { type_, name, .. } if type_.is_bool() && name == "False" => {
2387	                "false".to_doc()
2388	            }
2389	            Constant::Record { type_, .. } if type_.is_nil() => "undefined".to_doc(),
2390	
2391	            Constant::Record {
2392	                arguments,
2393	                module,
2394	                name,
2395	                tag,
2396	                type_,
2397	                ..
2398	            } => {
2399	                if module.is_none() && type_.is_result() {
2400	                    if tag == "Ok" {
2401	                        self.tracker.ok_used = true;
2402	                    } else {
2403	                        self.tracker.error_used = true;
2404	                    }
2405	                }
2406	
2407	                // If there's no arguments and the type is a function that takes
2408	                // arguments then this is the constructor being referenced, not the
2409	                // function being called.
2410	                if let Some(arity) = type_.fn_arity()
2411	                    && arguments.is_empty()
2412	                    && arity != 0
2413	                {
2414	                    let arity = arity as u16;
2415	                    return record_constructor(type_.clone(), None, name, arity, self.tracker);
2416	                }
2417	
2418	                // Record updates are fully expanded during type checking, so we just
2419	                // handle arguments
2420	                let field_values = arguments
2421	                    .iter()
2422	                    .map(|argument| self.guard_constant_expression(&argument.value))
2423	                    .collect_vec();
2424	                construct_record(
2425	                    module.as_ref().map(|(module, _)| module.as_str()),
2426	                    name,
2427	                    field_values,
2428	                )
2429	            }
2430	
2431	            Constant::BitArray { segments, .. } => {
2432	                self.constant_bit_array(segments, Context::Guard)
2433	            }
2434	
2435	            Constant::Var { name, .. } => self.local_var(name).to_doc(),
2436	
2437	            Constant::Int { .. }
2438	            | Constant::Float { .. }
2439	            | Constant::String { .. }
2440	            | Constant::RecordUpdate { .. }
2441	            | Constant::StringConcatenation { .. }
2442	            | Constant::Invalid { .. } => self.constant_expression(Context::Guard, expression),
2443	        }
2444	    }
2445	}
