2809	pub(crate) fn record_constructor<'a>(
2810	    type_: Arc<Type>,
2811	    qualifier: Option<&'a str>,
2812	    name: &'a str,
2813	    arity: u16,
2814	    tracker: &mut UsageTracker,
2815	) -> Document<'a> {
2816	    if qualifier.is_none() && type_.is_result_constructor() {
2817	        if name == "Ok" {
2818	            tracker.ok_used = true;
2819	        } else if name == "Error" {
2820	            tracker.error_used = true;
2821	        }
2822	    }
2823	    if type_.is_bool() && name == "True" {
2824	        "true".to_doc()
2825	    } else if type_.is_bool() {
2826	        "false".to_doc()
2827	    } else if type_.is_nil() {
2828	        "undefined".to_doc()
2829	    } else if arity == 0 {
2830	        match qualifier {
2831	            Some(module) => docvec!["new $", module, ".", name, "()"],
2832	            None => docvec!["new ", name, "()"],
2833	        }
2834	    } else {
2835	        let vars = (0..arity).map(|i| eco_format!("var{i}").to_doc());
2836	        let body = docvec![
2837	            "return ",
2838	            construct_record(qualifier, name, vars.clone()),
2839	            ";"
2840	        ];
2841	        docvec![
2842	            docvec![wrap_arguments(vars), " => {", break_("", " "), body]
2843	                .nest(INDENT)
2844	                .append(break_("", " "))
2845	                .group(),
2846	            "}",
2847	        ]
2848	    }
2849	}
