378	    fn switch(
379	        &mut self,
380	        var: &'a Variable,
381	        choices: &'a [(RuntimeCheck, Decision)],
382	        fallback: &'a Decision,
383	        fallback_check: &'a FallbackCheck,
384	    ) -> CaseBody<'a> {
385	        // If there's just a single choice we can just generate the code for
386	        // it: no need to do any checking, we know it must match!
387	        if choices.is_empty() {
388	            // However, if the choice had an associated check (that is, it was
389	            // not just a simple catch all) we need to keep track of all the
390	            // variables brought into scope by the (always) successfull check.
391	            if let FallbackCheck::RuntimeCheck { check } = fallback_check {
392	                self.variables.record_check_assignments(var, check);
393	            }
394	            return self.inside_new_scope(|this| this.decision(fallback));
395	        }
396	
397	        // Otherwise we'll have to generate a series of if-else to check which
398	        // pattern is going to match!
399	        let mut assignments = vec![];
400	        if !self.variables.is_bound_in_scope(var) {
401	            // If the variable we need to perform a check on is not already bound
402	            // in scope we will be binding it to a new made up name. This way we
403	            // can also reference this exact name in further checks instead of
404	            // recomputing the value each time.
405	            let name = self.variables.next_local_var(&ASSIGNMENT_VAR.into());
406	            let value = self.variables.get_value(var);
407	            self.variables.bind(name.clone(), var);
408	            assignments.push(let_doc(name, value.to_doc()))
409	        };
410	
411	        // Variable storing the character code for the first character of a string.
412	        // This is only declared if multiple patterns match on just the first
413	        // character, as it allows us to avoid calling `.startsWith` multiple times
414	        // and just call `.charCodeAt(0)` once, which is much faster.
415	        let first_character_variable = if multiple_single_character_prefix_checks(choices) {
416	            let name = self.variables.next_local_var(&ASSIGNMENT_VAR.into());
417	            let string = self.variables.get_value(var);
418	            let first_character = docvec![string, ".charCodeAt(0)"];
419	            assignments.push(let_doc(name.clone(), first_character));
420	            Some(name)
421	        } else {
422	            None
423	        };
424	
425	        let mut if_ = CaseBody::Statements(nil());
426	        for (i, (check, decision)) in choices.iter().enumerate() {
427	            self.variables.record_check_assignments(var, check);
428	
429	            // For each check we generate:
430	            // - the document to perform such check
431	            // - the body to run if the check is successful
432	            // - the assignments we need to bring all the bit array segments
433	            //   referenced by this check
434	            let (check_doc, body, mut segment_assignments) = self.inside_new_scope(|this| {
435	                let segment_assignments = this.variables.bit_array_segment_assignments(check);
436	
437	                // If the pattern matches on a single character, use the character
438	                // code instead of `.startsWith`.
439	                let check_doc = if let Some(code) = single_character_prefix_code(check) {
440	                    let first_character = if let Some(variable) = &first_character_variable {
441	                        variable.to_doc()
442	                    } else {
443	                        // This is the only single-character match in this `case`
444	                        // expression, so we don't bind it to a variable and just
445	                        // call `.charCodeAt` inline. This is still faster than
446	                        // `.startsWith`.
447	                        let string = this.variables.get_value(var);
448	                        docvec![string, ".charCodeAt(0)"]
449	                    };
450	
451	                    docvec![first_character, " === ", code]
452	                } else {
453	                    this.variables.runtime_check(var, check)
454	                };
455	
456	                let body = this.decision(decision);
457	                (check_doc, body, segment_assignments)
458	            });
459	            assignments.append(&mut segment_assignments);
460	
461	            let (check_doc, body) = match body {
462	                // If we have a statement like this:
463	                // ```javascript
464	                // if (x) {
465	                //   if (y) {
466	                //     ...
467	                //   }
468	                // }
469	                // ```
470	                //
471	                // We can transform it into:
472	                // ```javascript
473	                // if (x && y) {
474	                //   ...
475	                // }
476	                // ```
477	                CaseBody::If { check, body } => {
478	                    (docvec![check_doc, break_(" &&", " && "), check], body)
479	                }
480	
481	                // The following code is a pretty common pattern in the code
482	                // generated by decision trees:
483	                //
484	                // ```javascript
485	                // if (something) {
486	                //   if (something_else) {
487	                //     do_thing()
488	                //   } else {
489	                //     do_fallback()
490	                //   }
491	                // } else {
492	                //   do_fallback()
493	                // }
494	                // ```
495	                //
496	                // Here, the `do_fallback()` branch is repeated, which we want
497	                // to avoid if possible. In this case, we can transform the above
498	                // code into the following:
499	                //
500	                // ```javascript
501	                // if (something && something_else) {
502	                //   do_thing()
503	                // } else {
504	                //   do_fallback()
505	                // }
506	                // ```
507	                //
508	                // This only works if both `else` branches run the same code,
509	                // otherwise we would be losing information.
510	                // It also only works if the inner statement has only a single
511	                // `else` clause, and not multiple `else if`s.
512	                CaseBody::IfElse {
513	                    check,
514	                    if_body,
515	                    fallback_decision: decision,
516	                    ..
517	                } if decision == fallback => {
518	                    (docvec![check_doc, break_(" &&", " && "), check], if_body)
519	                }
520	
521	                if_else @ CaseBody::IfElse { .. } => (check_doc, if_else.into_doc()),
522	
523	                CaseBody::Statements(document) | CaseBody::IfElseChain(document) => {
524	                    (check_doc, document)
525	                }
526	            };
527	
528	            if_ = match if_ {
529	                // The first statement will always be an `if`
530	                _ if i == 0 => CaseBody::If {
531	                    check: check_doc,
532	                    body,
533	                },
534	                // If this is the second check, the `if` becomes `else if`
535	                CaseBody::If { .. } | CaseBody::IfElse { .. } => CaseBody::IfElseChain(docvec![
536	                    if_.into_doc(),
537	                    " else if (",
538	                    break_("", "")
539	                        .append(check_doc)
540	                        .nest(INDENT)
541	                        .append(break_("", ""))
542	                        .group(),
543	                    ") ",
544	                    break_block(body)
545	                ]),
546	                CaseBody::IfElseChain(document) | CaseBody::Statements(document) => {
547	                    CaseBody::IfElseChain(docvec![
548	                        document,
549	                        " else if (",
550	                        break_("", "")
551	                            .append(check_doc)
552	                            .nest(INDENT)
553	                            .append(break_("", ""))
554	                            .group(),
555	                        ") ",
556	                        break_block(body)
557	                    ])
558	                }
559	            };
560	        }
561	
562	        // In case there's some new variables we can extract after the
563	        // successful final check we store those. But we don't need to perform
564	        // the check itself: the type system ensures that, if we ever get here,
565	        // the check is going to match no matter what!
566	        if let FallbackCheck::RuntimeCheck { check } = fallback_check {
567	            self.variables.record_check_assignments(var, check);
568	        }
569	
570	        let else_body = self.inside_new_scope(|this| this.decision(fallback));
571	        let document = if else_body.is_empty() {
572	            if_
573	        } else if let CaseBody::If {
574	            check,
575	            body: if_body,
576	        } = if_
577	        {
578	            CaseBody::IfElse {
579	                check,
580	                if_body,
581	                else_body: else_body.document_after_else(),
582	                fallback_decision: fallback,
583	            }
584	        } else {
585	            CaseBody::IfElseChain(docvec![
586	                if_.into_doc(),
587	                " else ",
588	                else_body.document_after_else()
589	            ])
590	        };
591	
592	        if assignments.is_empty() {
593	            document
594	        } else {
595	            CaseBody::Statements(join_with_line(
596	                join(assignments, line()),
597	                document.into_doc(),
598	            ))
599	        }
600	    }
601	
602	    fn inside_new_scope<A, F>(&mut self, run: F) -> A
603	    where
604	        F: Fn(&mut Self) -> A,
605	    {
606	        // Since we use reassignment for `let assert`, we can't reset the scope
607	        // as it loses data about the assigned variables.
608	        let old_scope = match &self.kind {
609	            DecisionKind::Case { .. } => self
610	                .variables
611	                .expression_generator
612	                .current_scope_vars
613	                .clone(),
614	            DecisionKind::LetAssert { .. } => Default::default(),
615	        };
616	
617	        let old_names = self.variables.scoped_variable_names.clone();
618	        let old_segments = self.variables.segment_values.clone();
619	        let old_segment_names = self.variables.scoped_segment_names.clone();
620	        let output = run(self);
621	
622	        match &self.kind {
623	            DecisionKind::Case { .. } => {
624	                self.variables.expression_generator.current_scope_vars = old_scope
625	            }
626	            DecisionKind::LetAssert { .. } => {}
627	        }
628	
629	        self.variables.scoped_variable_names = old_names;
630	        self.variables.segment_values = old_segments;
631	        self.variables.scoped_segment_names = old_segment_names;
632	        output
633	    }
634	
635	    fn decision_guard(
636	        &mut self,
637	        guard: usize,
638	        if_true: &'a Body,
639	        if_false: &'a Decision,
640	    ) -> CaseBody<'a> {
641	        let DecisionKind::Case { clauses } = &self.kind else {
642	            unreachable!("Guards cannot appear in let assert decision trees")
643	        };
644	
645	        let guard = clauses
646	            .get(guard)
647	            .expect("invalid clause index")
648	            .guard
649	            .as_ref()
650	            .expect("missing guard");
651	
652	        // Before generating the if-else condition we want to generate all the
653	        // assignments that will be needed by the guard condition so we can rest
654	        // assured they are in scope and the guard check can use those.
655	        let guard_variables = guard.referenced_variables();
656	        let (check_bindings, if_true_bindings): (Vec<_>, Vec<_>) = if_true
657	            .bindings
658	            .iter()
659	            .partition(|(variable, _)| guard_variables.contains(variable));
660	
661	        let (check_bindings, check, if_true) = self.inside_new_scope(|this| {
662	            // check_bindings and if_true generation have to be in this scope so that pattern-bound
663	            // variables used in guards don't leak into other case branches (if_false).
664	            let check_bindings = this.variables.bindings_ref_doc(&check_bindings);
665	            let check = this.variables.expression_generator.guard(guard);
666	            // All the other bindings that are not needed by the guard check will
667	            // end up directly in the body of the if clause.
668	            let if_true_bindings = this.variables.bindings_ref_doc(&if_true_bindings);
669	            let if_true_body = this.body_expression(if_true.clause_index);
670	            let if_true = match if_true_body {
671	                BodyExpression::Variable(variable) => variable,
672	                BodyExpression::Expressions(if_true_body) => {
673	                    join_with_line(if_true_bindings, if_true_body)
674	                }
675	            };
676	            (check_bindings, check, if_true)
677	        });
678	
679	        let if_false_body = self.inside_new_scope(|this| this.decision(if_false));
680	
681	        // We can now piece everything together into a case body!
682	        let if_ = if if_false_body.is_empty() {
683	            CaseBody::If {
684	                check,
685	                body: if_true,
686	            }
687	        } else {
688	            CaseBody::IfElse {
689	                check,
690	                if_body: if_true,
691	                else_body: if_false_body.document_after_else(),
692	                fallback_decision: if_false,
693	            }
694	        };
695	
696	        if check_bindings.is_empty() {
697	            if_
698	        } else {
699	            CaseBody::Statements(join_with_line(check_bindings, if_.into_doc()))
700	        }
701	    }
