703	    fn assignment_no_match(
704	        &mut self,
705	        subject: Document<'a>,
706	        kind: &'a AssignmentKind<TypedExpr>,
707	        subject_location: SrcSpan,
708	        pattern_location: SrcSpan,
709	    ) -> Document<'a> {
710	        let AssignmentKind::Assert {
711	            location, message, ..
712	        } = kind
713	        else {
714	            unreachable!("inexhaustive let made it to code generation");
715	        };
716	
717	        let generator = &mut self.variables.expression_generator;
718	        let message = match message {
719	            None => string("Pattern match failed, no pattern matched the value."),
720	            Some(message) => generator
721	                .not_in_tail_position(Some(Ordering::Strict), |this| this.wrap_expression(message)),
722	        };
723	        generator.throw_error(
724	            "let_assert",
725	            &message,
726	            *location,
727	            [
728	                ("value", subject),
729	                ("start", location.start.to_doc()),
730	                ("end", subject_location.end.to_doc()),
731	                ("pattern_start", pattern_location.start.to_doc()),
732	                ("pattern_end", pattern_location.end.to_doc()),
733	            ],
734	        )
735	    }
736	}
