738	/// Returns the character code for the character being matched for patterns matching
739	/// on single-character string prefixes.
740	fn single_character_prefix_code(check: &RuntimeCheck) -> Option<u32> {
741	    match check {
742	        // On JavaScript, a single "character" is one that can be represented as
743	        // a single UTF-16 codepoint.
744	        RuntimeCheck::StringPrefix { prefix, rest } if utf16_no_escape_len(prefix) == 1 => {
745	            convert_string_escape_chars(prefix)
746	                .chars()
747	                .next()
748	                .map(|first| first as u32)
749	        }
750	        RuntimeCheck::Int { .. }
751	        | RuntimeCheck::Float { .. }
752	        | RuntimeCheck::String { .. }
753	        | RuntimeCheck::StringPrefix { .. }
754	        | RuntimeCheck::Tuple { .. }
755	        | RuntimeCheck::BitArray { .. }
756	        | RuntimeCheck::Variant { .. }
757	        | RuntimeCheck::NonEmptyList { .. }
758	        | RuntimeCheck::EmptyList => None,
759	    }
760	}
761	
762	/// Returns whether a `case` expression contains multiple patterns matching on
763	/// the first character of a string.
764	fn multiple_single_character_prefix_checks(choices: &[(RuntimeCheck, Decision)]) -> bool {
765	    let mut encountered_check = false;
766	
767	    for (check, _) in choices.iter() {
768	        if let RuntimeCheck::StringPrefix { prefix, .. } = check
769	            && utf16_no_escape_len(prefix) == 1
770	        {
771	            if encountered_check {
772	                return true;
773	            } else {
774	                encountered_check = true;
775	            }
776	        }
777	    }
778	
779	    false
780	}
