782	pub fn let_<'a>(
783	    compiled_case: &'a CompiledCase,
784	    subject: &'a TypedExpr,
785	    kind: &'a AssignmentKind<TypedExpr>,
786	    expression_generator: &mut Generator<'_, 'a>,
787	    pattern: &'a TypedPattern,
788	) -> Document<'a> {
789	    let scope_position = expression_generator.scope_position.clone();
790	    let mut variables = Variables::new(expression_generator, VariableAssignment::Reassign);
791	
792	    let assignment = variables.assign_let_subject(compiled_case, subject);
793	    let assignment_name = assignment.name();
794	    let assignments = vec![assignment];
795	
796	    let decision = CasePrinter {
797	        variables,
798	        assignments: &assignments,
799	        kind: DecisionKind::LetAssert {
800	            kind,
801	            subject_location: subject.location(),
802	            pattern_location: pattern.location(),
803	            subject: assignment_name.clone(),
804	        },
805	    }
806	    .decision(&compiled_case.tree);
807	
808	    // When we generate `let assert` statements, we want to produce code like
809	    // this:
810	    // ```javascript
811	    // let some_var;
812	    // let other_var;
813	    // if (condition_to_check_pattern) {
814	    //   some_var = x;
815	    //   other_var = y;
816	    // }
817	    // ```
818	    // This generates the code for binding the initial variables before the
819	    // check so the scoping of them is correct.
820	    //
821	    // We must generate this after we generate the code for the decision tree
822	    // itself as we might be re-binding variables which are used in the checks
823	    // to determine whether the pattern matches or not.
824	    let beginning_assignments = pattern.bound_variables().into_iter().map(|bound_variable| {
825	        docvec![
826	            "let ",
827	            expression_generator.local_var(&bound_variable.name()),
828	            ";",
829	            line()
830	        ]
831	    });
832	
833	    let doc = docvec![
834	        assignments_to_doc(assignments),
835	        concat(beginning_assignments),
836	        decision.into_doc()
837	    ];
838	
839	    match scope_position {
840	        expression::Position::Expression(_) | expression::Position::Statement => doc,
841	        expression::Position::Tail => docvec![doc, line(), "return ", assignment_name, ";"],
842	        expression::Position::Assign(variable) => {
843	            docvec![doc, line(), variable, " = ", assignment_name, ";"]
844	        }
845	    }
846	}
847	
848	enum VariableAssignment {
849	    Declare,
850	    Reassign,
851	}
852	
853	/// This is a useful piece of state that is kept separate from the generator
854	/// itself so we can reuse it both with `case`s and `let`s without rewriting
855	/// everything from scratch.
856	///
857	struct Variables<'generator, 'module, 'a> {
858	    expression_generator: &'generator mut Generator<'module, 'a>,
859	
860	    /// Whether to bind variables using `let` as we do in `case` expressions,
861	    /// or to reassign them as we do in `let assert` statements.
862	    variable_assignment: VariableAssignment,
863	
864	    /// All the pattern variables will be assigned a specific value: being bound
865	    /// to a constructor field, tuple element and so on. Pattern variables never
866	    /// end up in the generated code but we replace them with their actual value.
867	    /// We store those values as `EcoString`s in this map; the key is the pattern
868	    /// variable's unique id.
869	    ///
870	    variable_values: HashMap<usize, EcoString>,
871	
872	    /// The same happens for bit array segments. Unlike pattern variables, we
873	    /// identify those using their names and store their value as a `Document`.
874	    segment_values: HashMap<EcoString, Document<'a>>,
875	
876	    /// When we discover new variables after a runtime check we don't immediately
877	    /// generate assignments for each of them, because that could lead to wasted
878	    /// work. Let's consider the following check:
879	    ///
880	    /// ```txt
881	    /// a is Wibble(3, c, 1) -> c
882	    /// a is _ -> 1
883	    /// ```
884	    ///
885	    /// If we generated variables for it as soon as we enter its corresponding
886	    /// branch we would find ourselves with this piece of code:
887	    ///
888	    /// ```js
889	    /// if (a instanceof Wibble) {
890	    ///   let a$0 = wibble.0;
891	    ///   let a$1 = wibble.1;
892	    ///   let a$2 = wibble.2;
893	    ///
894	    ///   // and now we go on checking these new variables
895	    /// }
896	    /// ```
897	    ///
898	    /// However, by extracting all the fields immediately we might end up doing
899	    /// wasted work: as soon as we find out that `a$0 != 3` we don't even need
900	    /// to check the other fields, we know the pattern can't match! So we
901	    /// extracted two fields we're not even checking.
902	    ///
903	    /// To avoid this situation, we only bind a variable to a name right before
904	    /// we're checking it so we're sure we're never generating useless bindings.
905	    /// The previous example would become something like this:
906	    ///
907	    /// ```js
908	    /// if (a instanceof Wibble) {
909	    ///   let a$0 = wibble.0;
910	    ///   if (a$0 === 3) {
911	    ///     let a$2 = wibble.2
912	    ///     // further checks
913	    ///   } else {
914	    ///     return 1;
915	    ///   }
916	    /// }
917	    /// ```
918	    ///
919	    /// In this map we store the name a variable is bound to in the current
920	    /// scope. For example here we know that `wibble.0` is bound to the name
921	    /// `a$0`.
922	    ///
923	    scoped_variable_names: HashMap<usize, EcoString>,
924	
925	    /// Once again, this is the same as `scoped_variable_names` with the
926	    /// difference that a segment is identified by its name.
927	    ///
928	    scoped_segment_names: HashMap<EcoString, EcoString>,
929	}
930	
931	impl<'generator, 'module, 'a> Variables<'generator, 'module, 'a> {
932	    fn new(
933	        expression_generator: &'generator mut Generator<'module, 'a>,
934	        variable_assignment: VariableAssignment,
935	    ) -> Self {
936	        Variables {
937	            expression_generator,
938	            variable_assignment,
939	            variable_values: HashMap::new(),
940	            scoped_variable_names: HashMap::new(),
941	            segment_values: HashMap::new(),
942	            scoped_segment_names: HashMap::new(),
943	        }
944	    }
945	
946	    /// Give a unique name to each of the subjects of a case expression and keep
947	    /// track of each of those names in case it needs to be referenced later.
948	    ///
949	    fn assign_case_subjects(
950	        &mut self,
951	        compiled_case: &'a CompiledCase,
952	        subjects: &'a [TypedExpr],
953	    ) -> Vec<SubjectAssignment<'a>> {
954	        let assignments = subjects
955	            .iter()
956	            .map(|subject| assign_subject(self.expression_generator, subject, Ordering::Strict))
957	            .collect_vec();
958	
959	        for (variable, assignment) in compiled_case
960	            .subject_variables
961	            .iter()
962	            .zip(assignments.iter())
963	        {
964	            // We need to record the fact that each subject corresponds to a
965	            // pattern variable.
966	            self.set_value(variable, assignment.name());
967	            self.bind(assignment.name(), variable);
968	        }
969	
970	        assignments
971	    }
