1128	    /// Generates the document to perform a (possibly negated) runtime check on
1129	    /// the given variable.
1130	    ///
1131	    fn runtime_check(
1132	        &mut self,
1133	        variable: &Variable,
1134	        runtime_check: &'a RuntimeCheck,
1135	    ) -> Document<'a> {
1136	        let value = self.get_value(variable);
1137	
1138	        let equality = " === ";
1139	
1140	        match runtime_check {
1141	            RuntimeCheck::String { value: expected } => docvec![value, equality, string(expected)],
1142	            RuntimeCheck::Float {
1143	                float_value: expected,
1144	            } => docvec![value, equality, float_from_value(expected.value())],
1145	            RuntimeCheck::Int {
1146	                int_value: expected,
1147	            } => docvec![value, equality, expected.clone()],
1148	            RuntimeCheck::StringPrefix { prefix, .. } => {
1149	                docvec![value, ".startsWith(", string(prefix), ")"]
1150	            }
1151	
1152	            RuntimeCheck::BitArray { test } => match test {
1153	                // In this case we need to check that the remaining part of the
1154	                // bit array has a whole number of bytes.
1155	                BitArrayTest::CatchAllIsBytes { size_so_far } => {
1156	                    if size_so_far.is_zero() {
1157	                        docvec![value, ".bitSize % 8", equality, "0"]
1158	                    } else {
1159	                        let size_so_far = self.offset_to_doc(size_so_far, true);
1160	                        let remaining_bits = docvec![value, ".bitSize - ", size_so_far];
1161	                        docvec!["(", remaining_bits, ") % 8", equality, "0"]
1162	                    }
1163	                }
1164	
1165	                BitArrayTest::ReadSizeIsNotNegative { size } => {
1166	                    docvec![self.read_size_to_doc(size), " >= 0"]
1167	                }
1168	
1169	                BitArrayTest::SegmentIsFiniteFloat {
1170	                    read_action:
1171	                        ReadAction {
1172	                            from: start,
1173	                            size,
1174	                            endianness,
1175	                            ..
1176	                        },
1177	                } => {
1178	                    let start_doc = self.offset_to_doc(start, false);
1179	                    let end = match (start.constant_bits(), size.constant_bits()) {
1180	                        (Some(start), _) if start == BigInt::ZERO => self
1181	                            .read_size_to_doc(size)
1182	                            .expect("unexpected catch all size"),
1183	                        (Some(start), Some(end)) => (start + end).to_doc(),
1184	                        (_, _) => docvec![start_doc.clone(), " + ", self.read_size_to_doc(size)],
1185	                    };
1186	                    let check = self.bit_array_slice_to_float(value, start_doc, end, endianness);
1187	
1188	                    docvec!["Number.isFinite(", check, ")"]
1189	                }
1190	
1191	                // Here we need to make sure that the bit array has a specific
1192	                // size.
1193	                BitArrayTest::Size(SizeTest { operator, size }) => {
1194	                    let operator = match operator {
1195	                        SizeOperator::GreaterEqual => " >= ",
1196	                        SizeOperator::Equal => equality,
1197	                    };
1198	                    let size = self.offset_to_doc(size, false);
1199	                    docvec![value, ".bitSize", operator, size]
1200	                }
1201	
1202	                // Finally, here we need to check that a given portion of the
1203	                // bit array matches a given value.
1204	                BitArrayTest::Match(MatchTest {
1205	                    value: expected,
1206	                    read_action,
1207	                }) => match expected {
1208	                    BitArrayMatchedValue::LiteralString {
1209	                        value: _,
1210	                        encoding: _,
1211	                        bytes: expected,
1212	                    } => self.literal_string_segment_bytes_check(value, expected, read_action),
1213	                    BitArrayMatchedValue::LiteralFloat(expected) => {
1214	                        self.literal_float_segment_bytes_check(value, expected, read_action)
1215	                    }
1216	                    BitArrayMatchedValue::LiteralInt {
1217	                        value: expected, ..
1218	                    } => self.literal_int_segment_bytes_check(value, expected.clone(), read_action),
1219	                    BitArrayMatchedValue::Variable(..)
1220	                    | BitArrayMatchedValue::Discard(..)
1221	                    | BitArrayMatchedValue::Assign { .. } => {
1222	                        panic!("unreachable")
1223	                    }
1224	                },
1225	            },
1226	
1227	            // When checking on a tuple there's always going to be a single choice
1228	            // and the code generation will always skip generating the check for it
1229	            // as the type system ensures it must match.
1230	            RuntimeCheck::Tuple { .. } => unreachable!("tried generating runtime check for tuple"),
1231	
1232	            // Some variants like `Bool` and `Result` are special cased and checked
1233	            // in a different way from all other variants.
1234	            RuntimeCheck::Variant { match_, .. } if variable.type_.is_bool() => {
1235	                match match_.name().as_str() {
1236	                    "True" => value.to_doc(),
1237	                    _ => docvec!["!", value],
1238	                }
1239	            }
1240	
1241	            RuntimeCheck::Variant { match_, index, .. } => {
1242	                if variable.type_.is_result() && match_.module().is_none() {
1243	                    if *index == 0 {
1244	                        self.expression_generator.tracker.ok_used = true;
1245	                    } else {
1246	                        self.expression_generator.tracker.error_used = true;
1247	                    }
1248	                }
1249	
1250	                let qualification = match_
1251	                    .module()
1252	                    .map(|module| eco_format!("${module}."))
1253	                    .unwrap_or_default();
1254	
1255	                docvec![value, " instanceof ", qualification, match_.name()]
1256	            }
1257	
1258	            RuntimeCheck::NonEmptyList { .. } => {
1259	                self.expression_generator.tracker.list_non_empty_class_used = true;
1260	                docvec![value, " instanceof $NonEmpty"]
1261	            }
1262	
1263	            RuntimeCheck::EmptyList => {
1264	                self.expression_generator.tracker.list_empty_class_used = true;
1265	                docvec![value, " instanceof $Empty"]
1266	            }
1267	        }
1268	    }
