1270	    /// Turns a read action into a document that can be used to extract the
1271	    /// corresponding value from the given bit array and assign it to a
1272	    /// variable.
1273	    ///
1274	    fn read_action_to_doc(
1275	        &mut self,
1276	        bit_array: &Variable,
1277	        read_action: &ReadAction,
1278	    ) -> Document<'a> {
1279	        let ReadAction {
1280	            from,
1281	            size,
1282	            type_,
1283	            endianness,
1284	            signed,
1285	        } = read_action;
1286	        let bit_array = self.get_value(bit_array);
1287	        let from_bits = from.constant_bits();
1288	
1289	        // There's two special cases we need to take care of:
1290	        match (size, &from_bits) {
1291	            // If we're reading a single byte as un unsigned int from a byte aligned
1292	            // offset then we can optimise this call as a `.byteAt` call!
1293	            (ReadSize::ConstantBits(size), Some(from_bits))
1294	                if type_.is_int()
1295	                    && *size == BigInt::from(8)
1296	                    && !signed
1297	                    && from_bits.clone() % 8 == BigInt::ZERO =>
1298	            {
1299	                let from_byte: BigInt = from_bits / 8;
1300	                return docvec![bit_array, ".byteAt(", from_byte, ")"];
1301	            }
1302	
1303	            // If we're reading all the remaining bits/bytes of an array we'll
1304	            // take the remaining slice.
1305	            (ReadSize::RemainingBits | ReadSize::RemainingBytes, _) => {
1306	                return self.bit_array_slice(bit_array, from);
1307	            }
1308	
1309	            _ => (),
1310	        }
1311	
1312	        // Otherwise we'll take a regular slice out of the bit array, depending
1313	        // on the type of the segment.
1314	        let (start, end) =
1315	            if let (ReadSize::ConstantBits(size), Some(from_bits)) = (size, from_bits) {
1316	                // If both the start and and are known at compile time we can use
1317	                // those directly in the slice call and perform no addition at
1318	                // runtime.
1319	                let start = from_bits.clone().to_doc();
1320	                let end = (from_bits + size).to_doc();
1321	                (start, end)
1322	            } else {
1323	                // Otherwise we'll have to sum the variable part and the constant
1324	                // one to tell how long the slice should be.
1325	                let size = self.read_size_to_doc(size).expect("no variable size");
1326	                let start = self.offset_to_doc(from, false);
1327	                let end = if from.is_zero() {
1328	                    size
1329	                } else {
1330	                    docvec![start.clone(), " + ", size]
1331	                };
1332	                (start, end)
1333	            };
1334	
1335	        match type_ {
1336	            ReadType::Int => {
1337	                self.bit_array_slice_to_int(bit_array, start, end, endianness, *signed)
1338	            }
1339	            ReadType::Float => self.bit_array_slice_to_float(bit_array, start, end, endianness),
1340	            ReadType::BitArray => self.bit_array_slice_with_end(bit_array, from, end),
1341	            ReadType::String | ReadType::UtfCodepoint => {
1342	                panic!("invalid slice type made it to code generation: {type_:#?}")
1343	            }
1344	        }
1345	    }
1346	
1347	    fn offset_to_doc(&mut self, offset: &Offset, parenthesise: bool) -> Document<'a> {
1348	        if offset.is_zero() {
1349	            return "0".to_doc();
1350	        }
1351	
1352	        let mut pieces = vec![];
1353	        if offset.constant != BigInt::ZERO {
1354	            pieces.push(eco_string_int(offset.constant.to_string().into()));
1355	        }
1356	
1357	        for (variable, times) in offset
1358	            .variables
1359	            .iter()
1360	            .sorted_by(|(one, _), (other, _)| one.name().cmp(other.name()))
1361	        {
1362	            let mut variable = match variable {
1363	                VariableUsage::PatternSegment(segment_name, _) => self
1364	                    .get_segment_value(segment_name)
1365	                    .expect("segment referenced in a check before being created"),
1366	                VariableUsage::OutsideVariable(name) => self.local_var(name).to_doc(),
1367	            };
1368	            if *times != 1 {
1369	                variable = variable.append(" * ").append(*times)
1370	            }
1371	            pieces.push(variable.to_doc())
1372	        }
1373	
1374	        for calculation in offset.calculations.iter() {
1375	            let left = self.offset_to_doc(&calculation.left, true);
1376	            let right = self.offset_to_doc(&calculation.right, true);
1377	
1378	            let calculation = self.expression_generator.bin_op_with_doc_operands(
1379	                calculation.operator.to_bin_op(),
1380	                left,
1381	                right,
1382	                &crate::type_::int(),
1383	            );
1384	
1385	            if parenthesise {
1386	                pieces.push(calculation.surround("(", ")"))
1387	            } else {
1388	                pieces.push(calculation)
1389	            }
1390	        }
1391	
1392	        if pieces.len() > 1 && parenthesise {
1393	            docvec!["(", join(pieces, " + ".to_doc()), ")"]
1394	        } else {
1395	            join(pieces, " + ".to_doc())
1396	        }
1397	    }
