1399	    /// If the read size has a constant value (that is, it's not a "read all the
1400	    /// remaining bits/bytes") this returns a document representing that size.
1401	    ///
1402	    fn read_size_to_doc(&mut self, size: &ReadSize) -> Option<Document<'a>> {
1403	        match size {
1404	            ReadSize::ConstantBits(value) => Some(value.clone().to_doc()),
1405	            ReadSize::VariableBits { variable, unit } => {
1406	                let variable = self.local_var(variable.name());
1407	                Some(if *unit == 1 {
1408	                    variable.to_doc()
1409	                } else {
1410	                    docvec![variable, " * ", *unit as i64]
1411	                })
1412	            }
1413	            ReadSize::RemainingBits | ReadSize::RemainingBytes => None,
1414	
1415	            ReadSize::BinaryOperator {
1416	                left,
1417	                right,
1418	                operator,
1419	            } => {
1420	                let left = if self.read_size_must_be_wrapped(left) {
1421	                    self.read_size_to_doc(left)?.surround("(", ")")
1422	                } else {
1423	                    self.read_size_to_doc(left)?
1424	                };
1425	                let right = if self.read_size_must_be_wrapped(right) {
1426	                    self.read_size_to_doc(right)?.surround("(", ")")
1427	                } else {
1428	                    self.read_size_to_doc(right)?
1429	                };
1430	
1431	                Some(self.expression_generator.bin_op_with_doc_operands(
1432	                    operator.to_bin_op(),
1433	                    left,
1434	                    right,
1435	                    &crate::type_::int(),
1436	                ))
1437	            }
1438	        }
1439	    }
1440	
1441	    fn read_size_must_be_wrapped(&self, size: &ReadSize) -> bool {
1442	        match size {
1443	            ReadSize::ConstantBits(_) | ReadSize::RemainingBits | ReadSize::RemainingBytes => false,
1444	
1445	            ReadSize::VariableBits { unit, .. } => *unit != 1,
1446	            ReadSize::BinaryOperator { .. } => true,
1447	        }
1448	    }
