1513	    /// Generates the document that calls the `bitArraySlice` function, with
1514	    /// an end argument as well. If you need to take a slice that starts at a
1515	    /// given offset and read the entire array you can use `bit_array_slice`.
1516	    ///
1517	    fn bit_array_slice_with_end(
1518	        &mut self,
1519	        bit_array: impl Documentable<'a>,
1520	        from: &Offset,
1521	        end: impl Documentable<'a>,
1522	    ) -> Document<'a> {
1523	        self.expression_generator.tracker.bit_array_slice_used = true;
1524	        let from = self.offset_to_doc(from, false);
1525	        docvec!["bitArraySlice(", bit_array, ", ", from, ", ", end, ")"]
