1528	    /// Generates the document that calls the `bitArraySlice` function, starting
1529	    /// at a given offset. This will read the entire remaining bit of the array,
1530	    /// if you know that the slice should end at a given offset you can use
1531	    /// `bit_array_slice_with_end` instead.
1532	    ///
1533	    fn bit_array_slice(&mut self, bit_array: impl Documentable<'a>, from: &Offset) -> Document<'a> {
