1691	        match check {
1692	            RuntimeCheck::Int { .. }
1693	            | RuntimeCheck::Float { .. }
1694	            | RuntimeCheck::String { .. }
1695	            | RuntimeCheck::EmptyList => (),
1696	
1697	            RuntimeCheck::BitArray { test } => {
